class Solution:
    def canPlaceFlowers(self, flowerbed, n):
        bed = flowerbed[:]
        count = 0
        m = len(bed)
        for i in range(m):
            if bed[i] == 0:
                left = (i == 0) or bed[i - 1] == 0
                right = (i == m - 1) or bed[i + 1] == 0
                if left and right:
                    bed[i] = 1
                    count += 1
        return count >= n

