class Solution:
    def canPlaceFlowers(self, flowerbed, n):
        count = 0
        m = len(flowerbed)
        i = 0
        while i < m:
            if flowerbed[i] == 0 and (i == 0 or flowerbed[i - 1] == 0) and (i == m - 1 or flowerbed[i + 1] == 0):
                flowerbed[i] = 1
                count += 1
                if count >= n:
                    return True
                i += 2
            else:
                i += 1
        return count >= n

