var canPlaceFlowers = function(flowerbed, n) {
    let count = 0;
    const m = flowerbed.length;
    let i = 0;
    while (i < m) {
        if (flowerbed[i] === 0 && (i === 0 || flowerbed[i - 1] === 0) && (i === m - 1 || flowerbed[i + 1] === 0)) {
            flowerbed[i] = 1;
            count++;
            if (count >= n) return true;
            i += 2;
        } else {
            i += 1;
        }
    }
    return count >= n;
};
